ALTER TABLE leads ADD COLUMN ultimaInteracao TIMESTAMP NULL AFTER ultimoContato;

-- Copiar valores de ultimoContato para ultimaInteracao (migração de dados existentes)
UPDATE leads SET ultimaInteracao = ultimoContato WHERE ultimoContato IS NOT NULL;

-- Para leads sem ultimoContato, usar createdAt como base
UPDATE leads SET ultimaInteracao = createdAt WHERE ultimaInteracao IS NULL;

-- Criar índice para performance nas queries de transferência automática
CREATE INDEX ultima_interacao_idx ON leads(ultimaInteracao);

